mapper.select:
select clazz.id, clazz.name, clazz.room, emp.name master_name, clazz.begin_date, clazz.end_date, (case when now() > end_date then '已结课' when now() < begin_date then '未开班' else '在读中' end ) status, clazz.update_time from clazz left join emp on clazz.master_id = emp.id
and clazz.name like concat('%',#{name},'%')
and clazz.begin_date >= #{begin}
and clazz.end_date <= #{end}
